head.b:skin:
/*
 * Theme Name: CJR Premium E-Commerce Theme
 * Designer: Isuru Sithumina (Custom Glassmorphism Edition with Topbar & YouTube)
 * Platform: Google Blogger
 */

/* CSS variables matching the CloudNet pro layout */
:root {
  --bg-gradient: linear-gradient(135deg, #070a13 0%, #0d1527 100%);
  --glass-bg: rgba(15, 23, 42, 0.45);
  --glass-border: rgba(255, 255, 255, 0.08);
  --glass-hover-border: rgba(56, 189, 248, 0.3);
  --text-primary: #ffffff;
  --text-secondary: #94a3b8;
  --primary-accent: #1e70e0;
  --primary-accent-glow: rgba(30, 112, 224, 0.4);
  --success-green: #10b981;
  --success-green-glow: rgba(16, 185, 129, 0.4);
  --whatsapp-green: #25d366;
  --youtube-red: #ff0000;
  --font-display: 'Outfit', sans-serif;
  --font-body: 'Inter', sans-serif;
  --shadow-glass: 0 8px 32px 0 rgba(0, 0, 0, 0.37);
}

/* Light Mode Variables Override */
body.light-mode {
  --bg-gradient: linear-gradient(135deg, #f1f5f9 0%, #cbd5e1 100%);
  --glass-bg: rgba(255, 255, 255, 0.65);
  --glass-border: rgba(15, 23, 42, 0.08);
  --glass-hover-border: rgba(30, 112, 224, 0.4);
  --text-primary: #0f172a;
  --text-secondary: #475569;
  --shadow-glass: 0 8px 32px 0 rgba(15, 23, 42, 0.08);
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background: var(--bg-gradient);
  color: var(--text-primary);
  font-family: var(--font-body);
  min-height: 100vh;
  overflow-x: hidden;
  line-height: 1.6;
  position: relative;
  transition: background 0.3s ease, color 0.3s ease;
}

/* Decorative blurred blobs background */
.bg-blob {
  position: absolute;
  border-radius: 50%;
  filter: blur(120px);
  z-index: -1;
  opacity: 0.15;
  transition: opacity 0.3s ease;
}
body.light-mode .bg-blob {
  opacity: 0.06;
}
.blob-blue {
  top: 10%;
  right: 15%;
  width: 400px;
  height: 400px;
  background: var(--primary-accent);
}
.blob-purple {
  bottom: 20%;
  left: 10%;
  width: 500px;
  height: 500px;
  background: #8b5cf6;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  position: relative;
  z-index: 1;
}

/* Top bar above header */
.topbar {
  background: rgba(15, 23, 42, 0.4);
  border-bottom: 1px solid var(--glass-border);
  padding: 8px 0;
  font-size: 0.8rem;
  color: var(--text-secondary);
  font-family: var(--font-body);
  transition: background 0.3s ease;
  position: relative;
  z-index: 101;
}
body.light-mode .topbar {
  background: rgba(226, 232, 240, 0.5);
}
.topbar-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.topbar-left {
  display: flex;
  align-items: center;
  gap: 15px;
}
.topbar-left a {
  color: var(--text-secondary);
  text-decoration: none;
  display: flex;
  align-items: center;
  gap: 5px;
  transition: color 0.3s ease;
}
.topbar-left a:hover {
  color: var(--text-primary);
}
.topbar-divider {
  color: var(--glass-border);
}
.topbar-right {
  font-weight: 500;
  color: var(--text-primary);
}

/* Sticky Floating Header */
header {
  position: sticky;
  top: 20px;
  z-index: 100;
  margin-bottom: 40px;
}

.header-glass {
  background: var(--glass-bg);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid var(--glass-border);
  border-radius: 50px;
  padding: 12px 30px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  box-shadow: var(--shadow-glass);
  transition: all 0.3s ease;
}

.header-logo-container {
  display: flex;
  align-items: center;
  gap: 15px;
  text-decoration: none;
}

/* Silver coin blue robot logo */
.robot-logo-coin {
  width: 50px;
  height: 50px;
  border-radius: 50%;
  background: #f8fafc;
  border: 3px solid #cbd5e1;
  box-shadow: 0 4px 10px rgba(0,0,0,0.25), inset 0 2px 4px rgba(255,255,255,1);
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.robot-logo-svg {
  width: 36px;
  height: 36px;
}

.brand-name {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: 1.4rem;
  background: linear-gradient(to right, var(--text-primary), #93c5fd);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  letter-spacing: 0.5px;
}

/* Search Box - Ultra Liquid Glass iOS 26 visual theme */
.search-box {
  flex: 0 1 350px;
  position: relative;
}
.search-box input {
  width: 100%;
  padding: 12px 20px 12px 50px;
  border-radius: 30px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.08);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 0.95rem;
  outline: none;
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  box-shadow: inset 0 1px 1px rgba(255,255,255,0.1), 0 4px 15px rgba(0,0,0,0.2);
  transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}
body.light-mode .search-box input {
  background: rgba(255, 255, 255, 0.4);
  border: 1px solid rgba(15, 23, 42, 0.06);
  box-shadow: inset 0 1px 2px rgba(255,255,255,0.8), 0 4px 15px rgba(15, 23, 42, 0.05);
}
.search-box input:focus {
  background: rgba(255, 255, 255, 0.08);
  border-color: rgba(56, 189, 248, 0.5);
  box-shadow: inset 0 1px 1px rgba(255,255,255,0.1), 0 0 25px rgba(56, 189, 248, 0.25), 0 8px 30px rgba(0,0,0,0.3);
}
body.light-mode .search-box input:focus {
  background: rgba(255, 255, 255, 0.8);
  border-color: rgba(30, 112, 224, 0.4);
  box-shadow: inset 0 1px 2px rgba(255,255,255,0.8), 0 0 25px rgba(30, 112, 224, 0.15), 0 8px 30px rgba(15, 23, 42, 0.08);
}
.search-box i {
  position: absolute;
  left: 18px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--text-secondary);
  font-size: 1.05rem;
}

/* Header Actions: Toggles */
.header-actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.theme-toggle-btn, .cart-trigger {
  position: relative;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--glass-border);
  color: var(--text-primary);
  width: 45px;
  height: 45px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s ease;
}
body.light-mode .theme-toggle-btn, body.light-mode .cart-trigger {
  background: rgba(15, 23, 42, 0.04);
}
.theme-toggle-btn:hover, .cart-trigger:hover {
  background: var(--primary-accent);
  border-color: var(--primary-accent);
  color: white;
  box-shadow: 0 0 15px var(--primary-accent-glow);
  transform: scale(1.05);
}
.cart-badge {
  position: absolute;
  top: -5px;
  right: -5px;
  background: var(--success-green);
  color: white;
  font-size: 0.75rem;
  font-weight: 700;
  border-radius: 50%;
  min-width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 2px;
  box-shadow: 0 2px 5px rgba(0,0,0,0.3);
}

/* Category Navigation Button pop rising animation */
.categories-nav {
  margin-bottom: 30px;
}
.categories-scroll {
  display: flex;
  gap: 12px;
  overflow-x: auto;
  padding-bottom: 10px;
  scrollbar-width: thin;
  scrollbar-color: rgba(255,255,255,0.1) transparent;
}
.categories-scroll::-webkit-scrollbar {
  height: 4px;
}
.categories-scroll::-webkit-scrollbar-thumb {
  background: rgba(255,255,255,0.1);
  border-radius: 10px;
}
.cat-btn {
  white-space: nowrap;
  padding: 10px 22px;
  border-radius: 30px;
  background: var(--glass-bg);
  border: 1px solid var(--glass-border);
  color: var(--text-secondary);
  font-family: var(--font-display);
  font-weight: 500;
  cursor: pointer;
  text-decoration: none;
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  position: relative;
  overflow: hidden;
}
.cat-btn.active, .cat-btn:hover {
  background: linear-gradient(135deg, var(--primary-accent) 0%, #2563eb 100%);
  color: #fff;
  border-color: rgba(255, 255, 255, 0.15);
  box-shadow: 0 8px 20px var(--primary-accent-glow), inset 0 1px 1px rgba(255,255,255,0.3);
  transform: translateY(-5px) scale(1.03);
}
/* Shine reflection for active category buttons */
.cat-btn.active::before {
  content: '';
  position: absolute;
  top: 0;
  left: -50%;
  width: 200%;
  height: 100%;
  background: linear-gradient(to right, rgba(255,255,255,0) 0%, rgba(255,255,255,0.15) 50%, rgba(255,255,255,0) 100%);
  transform: skewX(-25deg);
  animation: gloss-shine 4s infinite linear;
}
@keyframes gloss-shine {
  0% { left: -100%; }
  100% { left: 100%; }
}

/* Hero Banner Section */
.hero-banner {
  background: linear-gradient(135deg, rgba(30, 112, 224, 0.1), rgba(139, 92, 246, 0.05));
  border: 1px solid var(--glass-border);
  border-radius: 24px;
  padding: 40px;
  margin-bottom: 40px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 30px;
  position: relative;
  overflow: hidden;
  backdrop-filter: blur(10px);
}
.hero-content h1 {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: 2.2rem;
  margin-bottom: 15px;
  line-height: 1.2;
}
.hero-content h1 span {
  background: linear-gradient(to right, #60a5fa, #34d399);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}
.hero-content p {
  color: var(--text-secondary);
  font-size: 1rem;
  max-width: 500px;
  margin-bottom: 25px;
}
.hero-btn {
  background: var(--primary-accent);
  color: white;
  border: none;
  padding: 12px 30px;
  border-radius: 30px;
  font-family: var(--font-display);
  font-weight: 600;
  cursor: pointer;
  box-shadow: 0 4px 15px var(--primary-accent-glow);
  transition: all 0.3s ease;
}
.hero-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px var(--primary-accent-glow);
}
.hero-logo-large {
  opacity: 0.85;
  animation: floatLogo 6s ease-in-out infinite;
}

/* Products Grid Section */
.section-title {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.8rem;
  margin-bottom: 25px;
  display: flex;
  align-items: center;
  gap: 10px;
}
.section-title::after {
  content: '';
  flex-grow: 1;
  height: 1px;
  background: var(--glass-border);
}

/* Category banner custom container */
.category-custom-section-container {
  background: var(--glass-bg);
  backdrop-filter: blur(12px);
  border: 1px solid var(--glass-border);
  border-radius: 20px;
  padding: 20px 30px;
  box-shadow: var(--shadow-glass);
}

.products-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 25px;
  margin-bottom: 60px;
}

/* E-Commerce Product Card */
.product-card {
  background: var(--glass-bg);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid var(--glass-border);
  border-radius: 20px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  position: relative;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 4px 20px rgba(0,0,0,0.15);
  overflow: hidden;
}
.product-card:hover {
  transform: translateY(-8px);
  border-color: var(--glass-hover-border);
  box-shadow: 0 12px 30px rgba(30, 112, 224, 0.15), 0 0 15px rgba(255,255,255,0.02);
}

.product-image-wrapper {
  width: 100%;
  height: 200px;
  border-radius: 14px;
  overflow: hidden;
  position: relative;
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid rgba(255, 255, 255, 0.03);
}
.product-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.5s ease;
}
.product-card:hover .product-image {
  transform: scale(1.08);
}

.product-image-fallback {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(255,255,255,0.02);
  color: var(--text-secondary);
  font-weight: 700;
  font-size: 1.2rem;
}

.product-category-tag {
  position: absolute;
  top: 10px;
  left: 10px;
  background: rgba(15, 23, 42, 0.7);
  backdrop-filter: blur(5px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  color: #38bdf8;
  font-size: 0.75rem;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.product-info {
  margin-top: 15px;
  display: flex;
  flex-direction: column;
  flex-grow: 1;
}

.product-title {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 1.1rem;
  color: var(--text-primary);
  margin-bottom: 8px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.product-description {
  color: var(--text-secondary);
  font-size: 0.85rem;
  margin-bottom: 15px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  height: 40px;
}

.product-price-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: auto;
  padding-top: 10px;
  border-top: 1px solid rgba(255,255,255,0.05);
  margin-bottom: 15px;
}

.product-price {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.25rem;
  color: #10b981;
}
body.light-mode .product-price {
  color: #059669;
}

.product-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}

.btn-pill {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 0.85rem;
  padding: 10px 5px;
  border-radius: 30px;
  border: none;
  cursor: pointer;
  text-align: center;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
}

.btn-cart {
  background: rgba(255, 255, 255, 0.05);
  color: var(--text-primary);
  border: 1px solid var(--glass-border);
}
body.light-mode .btn-cart {
  background: rgba(15, 23, 42, 0.05);
  border-color: rgba(15, 23, 42, 0.1);
}
.btn-cart:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: rgba(255, 255, 255, 0.2);
}
body.light-mode .btn-cart:hover {
  background: rgba(15, 23, 42, 0.08);
}

.btn-buy {
  background: linear-gradient(135deg, var(--primary-accent) 0%, #2563eb 100%);
  color: white;
  box-shadow: 0 4px 10px var(--primary-accent-glow);
}
.btn-buy:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 15px var(--primary-accent-glow);
}

/* Single Product Detail Page Layout */
.single-product-container {
  max-width: 1000px;
  margin: 40px auto;
  padding: 0 20px;
}

.product-detail-layout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 40px;
  background: var(--glass-bg);
  backdrop-filter: blur(16px);
  border: 1px solid var(--glass-border);
  border-radius: 30px;
  padding: 40px;
  box-shadow: var(--shadow-glass);
}

@media (max-width: 768px) {
  .product-detail-layout {
    grid-template-columns: 1fr;
    gap: 20px;
    padding: 20px;
  }
  .header-glass {
    padding: 10px 15px;
    border-radius: 30px;
  }
  .search-box {
    display: none;
  }
  .brand-name {
    font-size: 1.1rem;
  }
  .topbar {
    font-size: 0.75rem;
  }
  .topbar-right {
    display: none;
  }
}

.product-detail-image-wrapper {
  width: 100%;
  border-radius: 20px;
  overflow: hidden;
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid var(--glass-border);
  display: flex;
  align-items: center;
  justify-content: center;
}

.product-detail-image {
  width: 100%;
  max-height: 450px;
  object-fit: contain;
}

.product-image-fallback-large {
  width: 100%;
  height: 350px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(255,255,255,0.02);
  color: var(--text-secondary);
  font-weight: 700;
  font-size: 1.8rem;
}

.product-detail-right {
  display: flex;
  flex-direction: column;
}

.product-detail-category-tag {
  align-self: flex-start;
  background: rgba(56, 189, 248, 0.1);
  color: #38bdf8;
  font-size: 0.8rem;
  font-weight: 600;
  padding: 6px 16px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 20px;
  border: 1px solid rgba(56, 189, 248, 0.2);
}

.product-detail-title {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: 2.2rem;
  line-height: 1.2;
  margin-bottom: 15px;
}

.product-detail-price-box {
  margin-bottom: 25px;
  padding: 15px;
  background: rgba(255, 255, 255, 0.02);
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.04);
}

.product-detail-price {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: 2rem;
  color: #10b981;
}
body.light-mode .product-detail-price {
  color: #059669;
}

.product-detail-description {
  color: var(--text-secondary);
  font-size: 0.95rem;
  line-height: 1.7;
  margin-bottom: 30px;
}

.product-detail-actions {
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.btn-cart-large {
  background: rgba(255, 255, 255, 0.05);
  color: var(--text-primary);
  border: 1px solid var(--glass-border);
  padding: 15px;
  font-size: 1rem;
}
.btn-cart-large:hover {
  background: rgba(255, 255, 255, 0.1);
}

.btn-buy-large {
  background: linear-gradient(135deg, var(--primary-accent) 0%, #2563eb 100%);
  color: white;
  padding: 15px;
  font-size: 1rem;
  box-shadow: 0 4px 15px var(--primary-accent-glow);
}
.btn-buy-large:hover {
  box-shadow: 0 6px 20px var(--primary-accent-glow);
}

.btn-wa-large {
  background: var(--whatsapp-green);
  color: white;
  padding: 15px;
  font-size: 1rem;
  box-shadow: 0 4px 15px rgba(37, 211, 102, 0.3);
}
.btn-wa-large:hover {
  box-shadow: 0 6px 20px rgba(37, 211, 102, 0.4);
}

/* E-commerce Shopping Cart Sidebar Drawer */
.cart-drawer {
  position: fixed;
  top: 0;
  right: -420px;
  width: 100%;
  max-width: 400px;
  height: 100vh;
  background: rgba(8, 12, 22, 0.95);
  backdrop-filter: blur(25px);
  -webkit-backdrop-filter: blur(25px);
  border-left: 1px solid var(--glass-border);
  z-index: 1000;
  box-shadow: -10px 0 30px rgba(0, 0, 0, 0.5);
  transition: right 0.4s cubic-bezier(0.16, 1, 0.3, 1), background 0.3s ease;
  display: flex;
  flex-direction: column;
}
body.light-mode .cart-drawer {
  background: rgba(248, 250, 252, 0.97);
  box-shadow: -10px 0 30px rgba(15, 23, 42, 0.15);
}
.cart-drawer.open {
  right: 0;
}

.cart-drawer-header {
  padding: 24px;
  border-bottom: 1px solid var(--glass-border);
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.cart-drawer-header h2 {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.4rem;
  display: flex;
  align-items: center;
  gap: 10px;
}
.close-cart {
  background: none;
  border: none;
  color: var(--text-secondary);
  font-size: 1.2rem;
  cursor: pointer;
  width: 35px;
  height: 35px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;
}
.close-cart:hover {
  background: rgba(255,255,255,0.05);
  color: white;
}
body.light-mode .close-cart:hover {
  background: rgba(15, 23, 42, 0.05);
  color: var(--text-primary);
}

.cart-items-list {
  flex-grow: 1;
  overflow-y: auto;
  padding: 24px;
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.cart-item {
  display: flex;
  gap: 15px;
  align-items: center;
  background: rgba(255,255,255,0.02);
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  padding: 10px;
}
body.light-mode .cart-item {
  background: rgba(15, 23, 42, 0.02);
}
.cart-item-img {
  width: 60px;
  height: 60px;
  border-radius: 8px;
  object-fit: cover;
}
.cart-item-info {
  flex-grow: 1;
}
.cart-item-title {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 0.95rem;
  margin-bottom: 4px;
}
.cart-item-price {
  color: #10b981;
  font-size: 0.85rem;
  font-weight: 600;
}
body.light-mode .cart-item-price {
  color: #059669;
}
.cart-item-qty-controls {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 8px;
}
.qty-btn {
  width: 24px;
  height: 24px;
  border-radius: 50%;
  border: 1px solid var(--glass-border);
  background: rgba(255,255,255,0.05);
  color: var(--text-primary);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.8rem;
}
body.light-mode .qty-btn {
  background: rgba(15, 23, 42, 0.05);
}
.qty-btn:hover {
  background: var(--primary-accent);
  border-color: var(--primary-accent);
  color: white;
}
.qty-val {
  font-size: 0.9rem;
  font-weight: 600;
  min-width: 15px;
  text-align: center;
}
.remove-item {
  background: none;
  border: none;
  color: #ef4444;
  cursor: pointer;
  font-size: 0.9rem;
  padding: 5px;
  transition: all 0.3s ease;
}
.remove-item:hover {
  transform: scale(1.1);
}

.cart-empty {
  text-align: center;
  color: var(--text-secondary);
  margin-top: 50px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 15px;
}
.cart-empty i {
  font-size: 3rem;
  opacity: 0.3;
}

/* Checkout Details Form inside cart */
.checkout-form-section {
  padding: 20px 24px;
  border-top: 1px solid var(--glass-border);
  background: rgba(0, 0, 0, 0.1);
}
body.light-mode .checkout-form-section {
  background: rgba(15, 23, 42, 0.02);
}
.form-title {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 1rem;
  margin-bottom: 12px;
  color: var(--text-primary);
}
.form-group {
  margin-bottom: 12px;
}
.form-group input, .form-group textarea {
  width: 100%;
  padding: 8px 12px;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--glass-border);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 0.85rem;
  outline: none;
}
body.light-mode .form-group input, body.light-mode .form-group textarea {
  background: rgba(15, 23, 42, 0.03);
}
.form-group input:focus, .form-group textarea:focus {
  border-color: var(--primary-accent);
}

.cart-footer {
  padding: 24px;
  border-top: 1px solid var(--glass-border);
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.cart-total-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
}
.cart-total-val {
  color: #10b981;
  font-size: 1.3rem;
}
body.light-mode .cart-total-val {
  color: #059669;
}

.cart-checkout-actions {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.btn-checkout-wa {
  background: var(--whatsapp-green);
  color: white;
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1rem;
  padding: 12px;
  border-radius: 30px;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  box-shadow: 0 4px 15px rgba(37, 211, 102, 0.3);
  transition: all 0.3s ease;
}
.btn-checkout-wa:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(37, 211, 102, 0.4);
}

.btn-checkout-pp {
  background: linear-gradient(135deg, #ffc439 0%, #ffb300 100%);
  color: #003087;
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1rem;
  padding: 12px;
  border-radius: 30px;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  box-shadow: 0 4px 15px rgba(255, 196, 57, 0.3);
  transition: all 0.3s ease;
}
.btn-checkout-pp:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(255, 196, 57, 0.4);
}

/* Floating action buttons at bottom-right (WhatsApp and YouTube) */
.floating-actions {
  position: fixed;
  bottom: 30px;
  right: 30px;
  display: flex;
  flex-direction: column;
  gap: 12px;
  z-index: 99;
}

.btn-floating {
  width: 50px;
  height: 50px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.35rem;
  cursor: pointer;
  color: white;
  border: none;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
  transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}
.btn-floating:hover {
  transform: scale(1.1) rotate(5deg);
}

.float-wa {
  background: var(--whatsapp-green);
  animation: waPulse 2s infinite;
}

.float-yt {
  background: var(--youtube-red);
  box-shadow: 0 4px 15px rgba(255, 0, 0, 0.3);
}
.float-yt:hover {
  box-shadow: 0 6px 20px rgba(255, 0, 0, 0.5);
}

@keyframes waPulse {
  0% { box-shadow: 0 0 0 0 rgba(37, 211, 102, 0.7); }
  70% { box-shadow: 0 0 0 12px rgba(37, 211, 102, 0); }
  100% { box-shadow: 0 0 0 0 rgba(37, 211, 102, 0); }
}

/* Blogger Layout Added Product Styles */
.layout-products-container {
  margin-top: 40px;
}
.custom-layout-product {
  display: none;
}

/* Footer Styles */
footer {
  border-top: 1px solid var(--glass-border);
  background: rgba(5, 7, 13, 0.8);
  padding: 30px 20px;
  margin-top: 80px;
  text-align: center;
  transition: background 0.3s ease;
}
body.light-mode footer {
  background: rgba(226, 232, 240, 0.8);
}
.footer-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}
.footer-logo {
  display: flex;
  align-items: center;
  gap: 10px;
}
.footer-copyright {
  color: var(--text-secondary);
  font-size: 0.85rem;
  border-top: 1px solid rgba(255,255,255,0.05);
  padding-top: 15px;
  width: 100%;
}
body.light-mode .footer-copyright {
  border-top-color: rgba(15,23,42,0.06);
}
.footer-copyright span {
  color: var(--text-primary);
  font-weight: 500;
}

/* Overlay */
.drawer-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: rgba(0,0,0,0.6);
  backdrop-filter: blur(5px);
  z-index: 999;
  display: none;
}
.drawer-overlay.active {
  display: block;
}

/* Notifications popup */
.toast-notification {
  position: fixed;
  bottom: 100px;
  left: 30px;
  background: var(--glass-bg);
  backdrop-filter: blur(12px);
  border: 1px solid var(--success-green);
  color: var(--text-primary);
  padding: 12px 24px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  gap: 10px;
  box-shadow: var(--shadow-glass);
  transform: translateY(150px);
  transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  z-index: 9999;
}
.toast-notification.show {
  transform: translateY(0);
}
.toast-notification i {
  color: var(--success-green);
}

@keyframes floatLogo {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-12px); }
}

body.script:
//

// ==========================================
// STORE CONFIGURATION BLOCK (Sinhala/English)
// ==========================================
const STORE_CONFIG = {
  whatsappNumber: "94771234567",       // ඔබේ WhatsApp අංකය (ලංකාවේ අංකයට 94 යොදා 0 නැතුව ලියන්න)
  paypalEmail: "paypal-seller@cjr.com", // ඔබේ PayPal Email ලිපිනය
  currency: "LKR",                      // පෙන්විය යුතු මුදල් වර්ගය (LKR / USD)
  paypalConversionRate: 0.0031,         // LKR සිට USD වලට පරිවර්තනය වන අනුපාතය
  paypalCurrencyCode: "USD",            // PayPal ගනුදෙනු සඳහා Currency එක
  storeLocationUrl: "https://maps.google.com/?q=CJR+Electronics+Private+Limited", // Google Maps Link එක
  youtubeUrl: "https://youtube.com/@cjr_electronics", // ඔබේ YouTube Channel ලින්ක් එක - මෙය වෙනස් කළ විට YouTube Button එකේ ලින්ක් එක වෙනස් වේ!
  storeName: "CJR Electronics Private Limited",
  designerName: "Isuru Sithumina"
};

// Global Store variables
let cart = [];
let productsDatabase = {}; // Stores all parsed product attributes

document.addEventListener("DOMContentLoaded", function() {
  // 1. Load cart items
  const savedCart = localStorage.getItem("cjr_cart");
  if (savedCart) {
    try {
      cart = JSON.parse(savedCart);
    } catch (e) {
      cart = [];
    }
  }

  // 2. Load Light/Dark Mode preference
  initTheme();

  // 3. Bind links and configurations
  bindTopbarAndSettings();

  // 4. Highlight active category button based on URL path
  highlightActiveCategory();

  // 5. Parse and extract product parameters (Price, PayPal links)
  parseBloggerProducts();

  // 6. Parse layout-level HTML widgets
  parseLayoutWidgets();

  // 7. Dynamic "autoload/recommendations" product shuffler for home page view
  autoLoadRecommendedFeed();

  // 8. Update cart UI
  updateCartUI();
});

// Dynamic Binding of Settings to UI Links
function bindTopbarAndSettings() {
  // Store Location Link
  const locLink = document.getElementById("topbar-loc-link");
  if (locLink) locLink.href = STORE_CONFIG.storeLocationUrl;

  // Help Us Link
  const helpLink = document.getElementById("topbar-help-link");
  if (helpLink) {
    const msg = encodeURIComponent("Hello CJR Electronics Support! I need assistance.");
    helpLink.href = "https://wa.me/" + STORE_CONFIG.whatsappNumber + "?text=" + msg;
  }

  // Topbar Brand name
  const brandName = document.getElementById("topbar-brand-name");
  if (brandName) brandName.textContent = STORE_CONFIG.storeName;

  // Footer Copyright Spaced Text
  const copyrightText = document.getElementById("footer-copyright-text");
  if (copyrightText) {
    copyrightText.innerHTML = "&copy; Copyright <span>" + STORE_CONFIG.storeName + "</span> | Designed by <span>" + STORE_CONFIG.designerName + "</span>";
  }
}

// Dynamic product autoload reshuffle (simulating "most popular / views-based" dynamic catalog for home page)
function autoLoadRecommendedFeed() {
  const grid = document.getElementById("blogger-products-grid");
  if (!grid || window.location.pathname.includes("/search")) return;

  const cards = Array.from(grid.getElementsByClassName("product-card"));
  if (cards.length === 0) return;

  // Reshuffle catalog array elements dynamically to feel responsive and alive
  for (let i = cards.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    grid.appendChild(cards[j]); // Moving them in the DOM reshuffles the display order
  }
}

// Dark/Light Theme Switcher Logic
window.toggleTheme = function() {
  const body = document.body;
  const icon = document.getElementById("theme-icon");

  body.classList.toggle("light-mode");
  const isLight = body.classList.contains("light-mode");
  localStorage.setItem("cjr_theme", isLight ? "light" : "dark");

  if (isLight) {
    if (icon) icon.className = "fa-solid fa-moon";
  } else {
    if (icon) icon.className = "fa-solid fa-sun";
  }
};

function initTheme() {
  const savedTheme = localStorage.getItem("cjr_theme");
  const body = document.body;
  const icon = document.getElementById("theme-icon");

  if (savedTheme === "light") {
    body.classList.add("light-mode");
    if (icon) icon.className = "fa-solid fa-moon";
  } else {
    body.classList.remove("light-mode");
    if (icon) icon.className = "fa-solid fa-sun";
  }
}

// Highlight active category
function highlightActiveCategory() {
  const currentPath = window.location.pathname;
  const catBtns = document.querySelectorAll(".cat-btn");

  let matched = false;
  catBtns.forEach(btn => {
    const btnPath = btn.getAttribute("href");
    if (btnPath && currentPath.indexOf(btnPath) !== -1) {
      btn.classList.add("active");
      matched = true;
    } else {
      btn.classList.remove("active");
    }
  });

  if (!matched && (currentPath === "/" || currentPath === "")) {
    const homeBtn = document.querySelector('.cat-btn[href="/"]');
    if (homeBtn) homeBtn.classList.add("active");
  }
}

// Parse Blogger Posts to extract Prices, Links & description
function parseBloggerProducts() {
  const containers = document.querySelectorAll('.product-card, .single-product-container');

  containers.forEach(container => {
    const id = container.getAttribute('data-id');
    const title = container.getAttribute('data-title');
    const rawBodyEl = container.querySelector('.product-body-raw');

    if (!rawBodyEl || !id) return;

    const htmlContent = rawBodyEl.innerHTML;

    let price = 0;
    let currency = STORE_CONFIG.currency;
    let priceText = currency + " 0";

    const priceRegexRaw = /(?:Price|LKR|Rs\.|\$|රු)\s*:?\s*(\amp;d+(?:,\amp;d+)?(?:\.\amp;d+)?)/i;
    const priceRegexRaw2 = /(?:Price|LKR|Rs\.|\$|රු)\s*:?\s*(\d+(?:,\d+)?(?:\.\d+)?)/i;

    const priceMatch = htmlContent.match(priceRegexRaw2);
    if (priceMatch) {
      price = parseFloat(priceMatch[1].replace(/,/g, ''));
      priceText = currency + " " + price.toLocaleString();
    }

    let paypalLink = "";
    const paypalRegex = /href=["'](https?:\/\/(?:www\.)?(?:paypal\.com|paypal\.me)[^"']+)["']/i;
    const paypalMatch = htmlContent.match(paypalRegex);
    if (paypalMatch) {
      paypalLink = paypalMatch[1];
    }

    let rawText = rawBodyEl.textContent || rawBodyEl.innerText || "";
    const cleanedDesc = rawText.split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 0 && !line.match(/(price|paypal|mcash|ezcash|payhere|lkr|rs\.|රු\.)/i))
      .join(' ');

    let image = "";
    const imgEl = container.querySelector('.product-image, .product-detail-image');
    if (imgEl) {
      image = imgEl.getAttribute('src');
    }

    productsDatabase[id] = {
      id: id,
      title: title,
      price: price,
      image: image,
      paypalLink: paypalLink,
      description: cleanedDesc
    };

    const priceEl = document.getElementById("price-" + id);
    const descEl = document.getElementById("desc-" + id);
    const detailPriceEl = document.getElementById("det-price-" + id);
    const detailDescEl = document.getElementById("det-desc-" + id);

    if (priceEl) priceEl.textContent = priceText;
    if (descEl) descEl.textContent = cleanedDesc;
    if (detailPriceEl) detailPriceEl.textContent = priceText;
    if (detailDescEl) {
      detailDescEl.innerHTML = htmlContent.replace(/<a[^>]*paypal[^>]*>.*?<\/a>/ig, '')
                                           .replace(priceRegexRaw2, '');
    }
  });
}

// Parse products added via HTML Widgets in Layout
function parseLayoutWidgets() {
  const widgetSection = document.getElementById('layout-products-section');
  if (!widgetSection) return;

  const widgets = widgetSection.querySelectorAll('.widget');
  if (widgets.length === 0) return;

  let grid = document.getElementById('blogger-products-grid');
  if (!grid) {
    const catalogSec = document.getElementById('products-section');
    grid = document.createElement('div');
    grid.className = 'products-grid';
    grid.id = 'blogger-products-grid';
    catalogSec.appendChild(grid);
  }

  widgets.forEach((widget, index) => {
    const id = widget.getAttribute('id') || 'widget-' + index;
    const titleEl = widget.querySelector('h2.title');
    const contentEl = widget.querySelector('.widget-content');

    if (!contentEl) return;

    const widgetTitle = titleEl ? titleEl.textContent.trim() : 'Product';
    const html = contentEl.innerHTML;

    let price = 0;
    const priceRegexRaw = /(?:Price|LKR|Rs\.|\$|රු)\s*:?\s*(\d+(?:,\d+)?(?:\.\d+)?)/i;
    const priceMatch = html.match(priceRegexRaw);
    if (priceMatch) {
      price = parseFloat(priceMatch[1].replace(/,/g, ''));
    }

    let paypalLink = "";
    const paypalRegex = /href=["'](https?:\/\/(?:www\.)?(?:paypal\.com|paypal\.me)[^"']+)["']/i;
    const paypalMatch = html.match(paypalRegex);
    if (paypalMatch) {
      paypalLink = paypalMatch[1];
    }

    let image = "";
    const imgMatch = html.match(/src=["']([^"']+)["']/i);
    if (imgMatch) {
      image = imgMatch[1];
    } else {
      const urlMatch = html.match(/(https?:\/\/[^\s'"]+\.(?:jpg|jpeg|png|gif|webp))/i);
      if (urlMatch) image = urlMatch[0];
    }

    let textContent = contentEl.textContent || contentEl.innerText || "";
    const desc = textContent.replace(/https?:\/\/[^\s]+/g, '')
                             .replace(priceRegexRaw, '')
                             .trim();

    productsDatabase[id] = {
      id: id,
      title: widgetTitle,
      price: price,
      image: image,
      paypalLink: paypalLink,
      description: desc
    };

    const card = document.createElement('div');
    card.className = 'product-card';
    card.innerHTML = `
      <div class='product-image-wrapper'>
        <span class='product-category-tag'>Featured</span>
        ${image ? `<img class='product-image' src='${image}' alt='${widgetTitle}'>` : `<div class='product-image-fallback'>CJR Store</div>`}
      </div>
      <div class='product-info'>
        <h3 class='product-title' title='${widgetTitle}'>${widgetTitle}</h3>
        <p class='product-description'>${desc}</p>
        <div class='product-price-row'>
          <span class='product-price'>${STORE_CONFIG.currency} ${price.toLocaleString()}</span>
        </div>
        <div class='product-actions'>
          <button class='btn-pill btn-cart' onclick='addToCart("${id}")'>
            <i class='fa-solid fa-cart-plus'></i> Add Cart
          </button>
          <button class='btn-pill btn-buy' onclick='directBuyNow("${id}")'>
            <i class='fa-solid fa-bolt'></i> Buy Now
          </button>
        </div>
      </div>
    `;

    grid.appendChild(card);
    widget.style.display = 'none';
  });
}

// Toggle Cart Drawer
function toggleCart(open) {
  const drawer = document.getElementById("cart-drawer");
  const overlay = document.getElementById("cart-overlay");

  if (open) {
    drawer.classList.add("open");
    overlay.classList.add("active");
  } else {
    drawer.classList.remove("open");
    overlay.classList.remove("active");
  }
}

// Add to Cart
window.addToCart = function(productId) {
  const p = productsDatabase[productId];
  if (!p) return;

  const existingItem = cart.find(item => item.id === productId);
  if (existingItem) {
    existingItem.quantity += 1;
  } else {
    cart.push({
      id: p.id,
      title: p.title,
      price: p.price,
      image: p.image,
      paypalLink: p.paypalLink,
      quantity: 1
    });
  }

  saveCart();
  updateCartUI();
  showToast("Added to Cart: " + p.title);
};

// Save cart state
function saveCart() {
  localStorage.setItem("cjr_cart", JSON.stringify(cart));
}

// Update Cart UI
function updateCartUI() {
  const countEl = document.getElementById("cart-count");
  const listEl = document.getElementById("cart-items-list");
  const totalEl = document.getElementById("cart-total");
  const formEl = document.getElementById("checkout-form-container");

  const totalCount = cart.reduce((sum, item) => sum + item.quantity, 0);
  countEl.textContent = totalCount;

  listEl.innerHTML = "";

  if (cart.length === 0) {
    listEl.innerHTML = `
      <div class='cart-empty'>
        <i class='fa-solid fa-shopping-basket'></i>
        <p>Your shopping cart is empty</p>
      </div>
    `;
    totalEl.textContent = STORE_CONFIG.currency + " 0";
    formEl.style.display = "none";
    return;
  }

  formEl.style.display = "block";
  let subtotal = 0;

  cart.forEach(item => {
    const itemTotal = item.price * item.quantity;
    subtotal += itemTotal;

    const el = document.createElement("div");
    el.className = "cart-item";
    el.innerHTML = `
      <img class='cart-item-img' src='${item.image || ""}' alt='${item.title}'>
      <div class='cart-item-info'>
        <div class='cart-item-title'>${item.title}</div>
        <div class='cart-item-price'>${STORE_CONFIG.currency} ${item.price.toLocaleString()}</div>
        <div class='cart-item-qty-controls'>
          <button class='qty-btn' onclick='updateQty("${item.id}", -1)'><i class='fa-solid fa-minus'></i></button>
          <span class='qty-val'>${item.quantity}</span>
          <button class='qty-btn' onclick='updateQty("${item.id}", 1)'><i class='fa-solid fa-plus'></i></button>
          <button class='remove-item' onclick='removeItem("${item.id}")' style='margin-left: 10px;'>
            <i class='fa-solid fa-trash-can'></i>
          </button>
        </div>
      </div>
    `;
    listEl.appendChild(el);
  });

  totalEl.textContent = STORE_CONFIG.currency + " " + subtotal.toLocaleString();
}

window.updateQty = function(productId, delta) {
  const item = cart.find(item => item.id === productId);
  if (!item) return;

  item.quantity += delta;
  if (item.quantity <= 0) {
    removeItem(productId);
  } else {
    saveCart();
    updateCartUI();
  }
};

window.removeItem = function(productId) {
  cart = cart.filter(item => item.id !== productId);
  saveCart();
  updateCartUI();
};

window.handleSearchKeyPress = function(event) {
  if (event.key === "Enter") {
    const query = document.getElementById("store-search").value.trim();
    if (query.length > 0) {
      window.location.href = "/search?q=" + encodeURIComponent(query);
    }
  }
};

window.directBuyNow = function(productId) {
  const p = productsDatabase[productId];
  if (!p) return;

  if (p.paypalLink && p.paypalLink.trim().length > 0) {
    showToast("Redirecting to PayPal Checkout...");
    setTimeout(() => {
      window.open(p.paypalLink, '_blank');
    }, 1000);
  } else {
    const msg = encodeURIComponent(
      `*Order inquiry from CJR Electronics*\n` +
      `-------------------------------\n` +
      `I would like to purchase this product:\n` +
      `- 1 x *${p.title}* (${STORE_CONFIG.currency} ${p.price.toLocaleString()})\n\n` +
      `Please provide Bank / cash-on-delivery dispatch details.`
    );
    window.open(`https://wa.me/${STORE_CONFIG.whatsappNumber}?text=${msg}`, '_blank');
  }
};

window.directBuyWhatsApp = function(productId) {
  const p = productsDatabase[productId];
  if (!p) return;
  const msg = encodeURIComponent(
    `*Order request from CJR Electronics*\n` +
    `-------------------------------\n` +
    `Item: *${p.title}*\n` +
    `Price: ${STORE_CONFIG.currency} ${p.price.toLocaleString()}\n` +
    `Request Method: Cash on Delivery (COD)\n\n` +
    `Please ship this item to me.`
  );
  window.open(`https://wa.me/${STORE_CONFIG.whatsappNumber}?text=${msg}`, '_blank');
};

window.checkoutWhatsApp = function() {
  const name = document.getElementById("customer-name").value.trim();
  const phone = document.getElementById("customer-phone").value.trim();
  const address = document.getElementById("customer-address").value.trim();

  if (!name || !phone || !address) {
    alert("Please enter Name, Phone and Address fields to execute WhatsApp dispatch!");
    return;
  }

  let orderText = `*New Order - ${STORE_CONFIG.storeName}*\n`;
  orderText += `==========================================\n`;
  orderText += `*Customer Details:*\n`;
  orderText += `- *Name:* ${name}\n`;
  orderText += `- *Phone:* ${phone}\n`;
  orderText += `- *Address:* ${address}\n\n`;
  orderText += `*Ordered Items:*\n`;

  let total = 0;
  cart.forEach(item => {
    const itemTotal = item.price * item.quantity;
    total += itemTotal;
    orderText += `- ${item.quantity} x *${item.title}* (${STORE_CONFIG.currency} ${item.price.toLocaleString()} each) = ${STORE_CONFIG.currency} ${itemTotal.toLocaleString()}\n`;
  });

  orderText += `\n*Total Amount:* ${STORE_CONFIG.currency} ${total.toLocaleString()}\n`;
  orderText += `*Method:* Cash on Delivery (COD) / Bank Transfer\n`;
  orderText += `==========================================`;

  const encodedMsg = encodeURIComponent(orderText);
  const whatsappUrl = `https://wa.me/${STORE_CONFIG.whatsappNumber}?text=${encodedMsg}`;

  cart = [];
  saveCart();
  updateCartUI();
  toggleCart(false);

  window.open(whatsappUrl, '_blank');
};

window.checkoutPayPal = function() {
  if (cart.length === 0) return;

  const ppForm = document.getElementById("paypal-cart-form");
  const ppBusiness = document.getElementById("pp-form-business");
  const ppCurrency = document.getElementById("pp-form-currency");

  ppBusiness.value = STORE_CONFIG.paypalEmail;

  const oldInputs = ppForm.querySelectorAll(".dynamic-item-input");
  oldInputs.forEach(el => el.remove());

  let needsConversion = (STORE_CONFIG.currency === 'LKR');
  ppCurrency.value = needsConversion ? "USD" : STORE_CONFIG.currency;

  cart.forEach((item, index) => {
    const itemIndex = index + 1;

    const nameInput = document.createElement("input");
    nameInput.type = "hidden";
    nameInput.name = "item_name_" + itemIndex;
    nameInput.value = item.title;
    nameInput.className = "dynamic-item-input";

    const amtInput = document.createElement("input");
    amtInput.type = "hidden";
    amtInput.name = "amount_" + itemIndex;
    const priceVal = needsConversion ? (item.price * STORE_CONFIG.paypalConversionRate).toFixed(2) : item.price;
    amtInput.value = priceVal;
    amtInput.className = "dynamic-item-input";

    const qtyInput = document.createElement("input");
    qtyInput.type = "hidden";
    qtyInput.name = "quantity_" + itemIndex;
    qtyInput.value = item.quantity;
    qtyInput.className = "dynamic-item-input";

    ppForm.appendChild(nameInput);
    ppForm.appendChild(amtInput);
    ppForm.appendChild(qtyInput);
  });

  showToast("Redirecting to secure PayPal Checkout page...");

  setTimeout(() => {
    ppForm.submit();
    cart = [];
    saveCart();
    updateCartUI();
    toggleCart(false);
  }, 1000);
};

window.openWhatsAppChat = function() {
  const msg = encodeURIComponent("Hello CJR Electronics! I would like to make an inquiry.");
  window.open(`https://wa.me/${STORE_CONFIG.whatsappNumber}?text=${msg}`, '_blank');
};

window.openYouTubeChannel = function() {
  window.open(STORE_CONFIG.youtubeUrl, '_blank');
};

function showToast(message) {
  const toast = document.getElementById("toast-notif");
  const msgEl = document.getElementById("toast-message");
  if (toast && msgEl) {
    msgEl.textContent = message;
    toast.classList.add("show");

    setTimeout(() => {
      toast.classList.remove("show");
    }, 3000);
  }
}
